1	export type Cell = [number, number];
2	
3	const NEIGHBORS_TO_SURVIVE = 2;
4	const NEIGHBORS_TO_BIRTH = 3;
5	
6	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
7	
8	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [ 0, -1],          [ 0, 1],
11	  [ 1, -1], [ 1, 0], [ 1, 1],
12	];
13	
14	type NeighborTally = { cell: Cell; count: number };
15	
16	const tallyLiveNeighbors = (cells: Cell[]): Map<string, NeighborTally> => {
17	  const tallies = new Map<string, NeighborTally>();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const k = cellKey(neighbor);
22	      const tally = tallies.get(k) ?? { cell: neighbor, count: 0 };
23	      tally.count += 1;
24	      tallies.set(k, tally);
25	    }
26	  }
27	  return tallies;
28	};
29	
30	const isAliveNext = (neighborCount: number, isAlive: boolean): boolean =>
31	  neighborCount === NEIGHBORS_TO_BIRTH ||
32	  (neighborCount === NEIGHBORS_TO_SURVIVE && isAlive);
33	
34	export function nextGeneration(cells: Cell[]): Cell[] {
35	  const alive = new Set(cells.map(cellKey));
36	  const tallies = tallyLiveNeighbors(cells);
37	
38	  const next: Cell[] = [];
39	  for (const [k, { cell, count }] of tallies) {
40	    if (isAliveNext(count, alive.has(k))) next.push(cell);
41	  }
42	  return next;
43	}
44

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty input produces empty output", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (Rule 1, each has 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 4 neighbors dies (Rule 3 - overpopulation)", () => {
15	    const cells: Cell[] = [[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]];
16	    const result = nextGeneration(cells);
17	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
18	  });
19	  it("dead cell with exactly 3 live neighbors becomes alive (Rule 4 - reproduction)", () => {
20	    const cells: Cell[] = [[0, 0], [1, 0], [0, 1]];
21	    const result = nextGeneration(cells);
22	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(true);
23	  });
24	  it("live cell with 2 live neighbors survives (Rule 2)", () => {
25	    const cells: Cell[] = [[0, 0], [1, 0], [2, 0]];
26	    const result = nextGeneration(cells);
27	    expect(result.some(([x, y]) => x === 1 && y === 0)).toBe(true);
28	  });
29	  it("live cell with 3 live neighbors survives (Rule 2)", () => {
30	    const cells: Cell[] = [[0, 0], [1, 0], [2, 0], [1, 1]];
31	    const result = nextGeneration(cells);
32	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(true);
33	  });
34	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]", () => {
35	    const cells: Cell[] = [[0, 0], [0, 1], [0, 2]];
36	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
37	    const sortKey = (c: Cell) => `${c[0]},${c[1]}`;
38	    const byKey = (a: Cell, b: Cell) => sortKey(a).localeCompare(sortKey(b));
39	    expect(nextGeneration(cells).sort(byKey)).toEqual(expected.sort(byKey));
40	  });
41	  it("block is a still life — [(0,0),(1,0),(0,1),(1,1)] stays unchanged", () => {
42	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
43	    const result = nextGeneration(block);
44	    const sortKey = (c: Cell) => `${c[0]},${c[1]}`;
45	    expect([...result].sort((a, b) => sortKey(a).localeCompare(sortKey(b))))
46	      .toEqual([...block].sort((a, b) => sortKey(a).localeCompare(sortKey(b))));
47	  });
48	  it("handles negative coordinates", () => {
49	    const cells: Cell[] = [[-5, -5], [-5, -4], [-5, -3]];
50	    const expected: Cell[] = [[-6, -4], [-5, -4], [-4, -4]];
51	    const sortKey = (c: Cell) => `${c[0]},${c[1]}`;
52	    const byKey = (a: Cell, b: Cell) => sortKey(a).localeCompare(sortKey(b));
53	    expect(nextGeneration(cells).sort(byKey)).toEqual(expected.sort(byKey));
54	  });
55	});
